import './App.css';
import video_bg from './assets/home-bg.mp4';
import About from './about';
import Navbar from './components/Navbar/Navbar';
import { BrowserRouter as Routex, Routes, Route, BrowserRouter } from "react-router-dom";

function App() {
  return (
    <BrowserRouter>
      <div className="App">
        <Navbar />

        <About />
      </div>
      <Routes>
        <Route path="/about" component={About} />
        {/* <Route path="/home" component={Home} /> */}
      </Routes>
    </BrowserRouter>
  );
}

export default App;
